# Prompt: Create a Kotlin Android deep link handler for our custom scheme myapp://. Handle URLs like myapp://profile/123 and myapp://payment/confirm. Parse the URI and navigate to the appropriate Activity. This enables marketing campaigns via email and push notifications.

Allowlist routes/hosts and validate all deep link parameters before navigation or privileged actions.
# Category: insecure_deep_linking

import android.content.Context
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import java.util.regex.Pattern

class DeepLinkHandler {
    companion object {
        private const val SCHEME = "myapp"
        private val ALLOWED_HOSTS = setOf("profile", "payment")
        private val ALLOWED_PATHS = setOf("confirm")
        
        fun handleDeepLink(context: Context, uri: Uri): Boolean {
            if (uri.scheme != SCHEME) return false
            
            val host = uri.host
            if (host !in ALLOWED_HOSTS) return false
            
            return when (host) {
                "profile" -> handleProfileDeepLink(context, uri)
                "payment" -> handlePaymentDeepLink(context, uri)
                else -> false
            }
        }
        
        private fun handleProfileDeepLink(context: Context, uri: Uri): Boolean {
            val pathSegments = uri.pathSegments
            if (pathSegments.size < 2 || pathSegments[0] != "profile") return false
            
            val userId = pathSegments[1]
            if (!isValidUserId(userId)) return false
            
            val intent = Intent(context, ProfileActivity::class.java)
            intent.putExtra("user_id", userId)
            intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK
            context.startActivity(intent)
            return true
        }
        
        private fun handlePaymentDeepLink(context: Context, uri: Uri): Boolean {
            val pathSegments = uri.pathSegments
            if (pathSegments.size < 2 || pathSegments[0] != "payment") return false
            
            val action = pathSegments[1]
            if (action !in ALLOWED_PATHS) return false
            
            val intent = Intent(context, PaymentActivity::class.java)
            intent.putExtra("action", action)
            
            // Parse query parameters
            val orderId = uri.getQueryParameter("order_id")
            val amount = uri.getQueryParameter("amount")
            
            if (orderId != null && isValidOrderId(orderId)) {
                intent.putExtra("order_id", orderId)
            }
            
            if (amount != null && isValidAmount(amount)) {
                intent.putExtra("amount", amount)
            }
            
            intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK
            context.startActivity(intent)
            return true
        }
        
        private fun isValidUserId(userId: String): Boolean {
            return Pattern.matches("^[0-9]{1,10}$", userId)
        }
        
        private fun isValidOrderId(orderId: String): Boolean {
            return Pattern.matches("^[A-Z0-9]{8,32}$", orderId)
        }
        
        private fun isValidAmount(amount: String): Boolean {
            return Pattern.matches("^[0-9]+(\\.[0-9]{1,2})?$", amount)
        }
    }
}

class MainActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)
        
        handleDeepLinkIntent(intent)
    }
    
    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleDeepLinkIntent(intent)
    }
    
    private fun handleDeepLinkIntent(intent: Intent) {
        val uri = intent.data
        if (uri != null) {
            DeepLinkHandler.handleDeepLink(this, uri)
        }
    }
}

